        if flags & 4 != 0 { pf = pf | PteFlags::READ; }
        if flags & 2 != 0 { pf = pf | PteFlags::WRITE; }
        if flags & 1 != 0 { pf = pf | PteFlags::EXECUTE; }
        let va = vaddr.as_usize();
        let a = va & !(PAGE_SIZE-1);
        let e = (va + memsz + PAGE_SIZE-1) & !(PAGE_SIZE-1);
        for pg in (a..e).step_by(PAGE_SIZE) {
            let pa = alloc_page(); unsafe { (pa.as_usize() as *mut u8).write_bytes(0, PAGE_SIZE); }
            // Source range in segdata
            let src_start = pg.max(va) - va;
            let src_end = ((pg+PAGE_SIZE).min(va+segdata.len())).saturating_sub(va);
            // Destination offset in page
            let dst_off = if va > pg { va - pg } else { 0 };
            if src_end > src_start {
                unsafe {
                    core::ptr::copy_nonoverlapping(
                        segdata.as_ptr().add(src_start),
                        (pa.as_usize() + dst_off) as *mut u8,
                        src_end - src_start,
                    );
                }
            }
            upt.map(VirtAddr::new(pg), pa, pf);
        }
    });

