use core::arch::global_asm;

global_asm!(
    ".section .text.entry",
    ".globl _start",
    "_start:",
    "    la sp, boot_stack_top",
    "    call arch_init",
    "    j .",
    ".section .bss.stack",
    ".align 12",
    "boot_stack:",
    ".zero 131072",
    "boot_stack_top:",
);

global_asm!(
    ".section .text.trap",
    ".globl trap_vector",
    ".align 4",
    "trap_vector:",
    // Swap sp (user) with sscratch (kernel sp)
    "    csrrw sp, sscratch, sp",
    // sp = kernel sp; allocate TrapFrame (304 bytes)
    "    addi sp, sp, -304",
    // Save regs x0-x31 (offsets 0-255)
    "    sd zero, 0(sp)",       // x0
    "    sd ra, 8(sp)",          // x1
    // Save t0 temporarily in user_satp slot (offset 296)
    "    sd t0, 296(sp)",
    // Get user sp from sscratch → t0
    "    csrr t0, sscratch",
    "    sd t0, 16(sp)",         // x2 = user sp
    // Restore user t0 from temp, save to x5 slot
    "    ld t0, 296(sp)",
    "    sd t0, 40(sp)",         // x5 = user t0
    "    sd gp, 24(sp)",         // x3
    "    sd tp, 32(sp)",         // x4
    "    sd t1, 48(sp)",         // x6
    "    sd t2, 56(sp)",         // x7
    "    sd s0, 64(sp)",         // x8
    "    sd s1, 72(sp)",         // x9
    "    sd a0, 80(sp)",         // x10
    "    sd a1, 88(sp)",         // x11
    "    sd a2, 96(sp)",         // x12
    "    sd a3, 104(sp)",        // x13
    "    sd a4, 112(sp)",        // x14
    "    sd a5, 120(sp)",        // x15
    "    sd a6, 128(sp)",        // x16
    "    sd a7, 136(sp)",        // x17
    "    sd s2, 144(sp)",        // x18
    "    sd s3, 152(sp)",        // x19
    "    sd s4, 160(sp)",        // x20
    "    sd s5, 168(sp)",        // x21
    "    sd s6, 176(sp)",        // x22
    "    sd s7, 184(sp)",        // x23
    "    sd s8, 192(sp)",        // x24
    "    sd s9, 200(sp)",        // x25
    "    sd s10, 208(sp)",       // x26
    "    sd s11, 216(sp)",       // x27
    "    sd t3, 224(sp)",        // x28
    "    sd t4, 232(sp)",        // x29
    "    sd t5, 240(sp)",        // x30
    "    sd t6, 248(sp)",        // x31

    // Save CSRs (offsets 256-295)
    "    csrr t0, sepc",
    "    sd t0, 256(sp)",        // sepc
    "    csrr t0, sstatus",
    "    sd t0, 264(sp)",        // sstatus
    "    csrr t0, scause",
    "    sd t0, 272(sp)",        // scause
    "    csrr t0, stval",
    "    sd t0, 280(sp)",        // stval
    // kernel_sp = sp before frame allocation
    "    addi t0, sp, 304",
    "    sd t0, 288(sp)",        // kernel_sp
    "    csrr t0, satp",
    "    sd t0, 296(sp)",        // user_satp

    // Save frame pointer in sscratch for trap_return
    "    csrw sscratch, sp",

    // a0 = &TrapFrame
