    "    csrw satp, t0",
    "    sfence.vma",

    // Restore CSRs
    "    ld t0, 256(sp)",
    "    csrw sepc, t0",
	    "    ld t0, 264(sp)",
	    "    csrw sstatus, t0",
	    "    ld t0, 288(sp)",
	    "    csrw sscratch, t0",

	    // Restore regs
    "    ld ra, 8(sp)",
    "    ld gp, 24(sp)",
    "    ld tp, 32(sp)",
    "    ld t0, 40(sp)",
    "    ld t1, 48(sp)",
    "    ld t2, 56(sp)",
    "    ld s0, 64(sp)",
    "    ld s1, 72(sp)",
    "    ld a0, 80(sp)",
    "    ld a1, 88(sp)",
    "    ld a2, 96(sp)",
    "    ld a3, 104(sp)",
    "    ld a4, 112(sp)",
