    "    ld s7, 184(sp)",
    "    ld s8, 192(sp)",
    "    ld s9, 200(sp)",
    "    ld s10, 208(sp)",
    "    ld s11, 216(sp)",
    "    ld t3, 224(sp)",
    "    ld t4, 232(sp)",
    "    ld t5, 240(sp)",
    "    ld t6, 248(sp)",

    // Restore user sp (from regs[2] = offset 16)
    "    ld sp, 16(sp)",

    // Back to user mode
