const PHYS_MEM_START: usize = 0x80000000;
const PHYS_MEM_SIZE: usize = 256 * 1024 * 1024;

pub fn memory_range() -> (usize, usize) {
    let kernel_end = unsafe { &_end as *const u8 as usize };
    let free_start = (kernel_end + 0xFFF) & !0xFFF;
    let mem_end = PHYS_MEM_START + PHYS_MEM_SIZE;
    let free_size = mem_end - free_start;
    (free_start, free_size)
}

pub fn putchar(c: u8) {
    unsafe {
        core::arch::asm!(
            "li a7, 1",
            "mv a0, {0}",
            "ecall",
            in(reg) c as u64,
            out("a7") _,
            out("a0") _,
        );
    }
}

pub fn init_trap() {
    unsafe {
        core::arch::asm!(
            "la t0, trap_vector",
            "csrw stvec, t0",
            out("t0") _,
        );
    }
    crate::println!("trap: stvec set");
}

#[no_mangle]
extern "C" fn arch_init() -> ! {
    crate::kernel_main();
}

pub fn arch_shutdown() -> ! {
    unsafe {
        core::arch::asm!(
            "li a7, 8",
            "ecall",
            in("a7") 8u64,
        );
    }
    loop {}
}

