const SCAUSE_ECALL_U: usize = 8;
const SCAUSE_ECALL_S: usize = 9;
const SCAUSE_INST_PAGE_FAULT: usize = 12;
const SCAUSE_LOAD_PAGE_FAULT: usize = 13;
const SCAUSE_STORE_PAGE_FAULT: usize = 15;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_SYS: usize = 11;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_TLBI: usize = 1;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_PIL: usize = 2;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_PIS: usize = 3;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_PIF: usize = 4;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_PME: usize = 7;
#[cfg(target_arch = "loongarch64")]
const LA_ECODE_ADE: usize = 8;
#[cfg(target_arch = "loongarch64")]
const LA_REAL_ELF_TRACE: bool = option_env!("LA_REAL_ELF_TRACE").is_some();

#[no_mangle]
extern "C" fn handle_trap(tf: &mut TrapFrame) {
    let scause = tf.scause;
    let stval = tf.stval;

    #[cfg(target_arch = "loongarch64")]
    {
        return handle_loongarch_trap(tf, scause, stval);
    }

    #[cfg(target_arch = "riscv64")]
    match scause {
        SCAUSE_ECALL_U => {
            tf.sepc += 4;
            // Enable SUM for user memory access (RISC-V only)
            unsafe {
                const SSTATUS_SUM: usize = 1 << 18;
                core::arch::asm!("csrs sstatus, {}", in(reg) SSTATUS_SUM);
            }
            crate::syscall::syscall(tf);
            unsafe {
                const SSTATUS_SUM: usize = 1 << 18;
                core::arch::asm!("csrc sstatus, {}", in(reg) SSTATUS_SUM);
            }
        }
        SCAUSE_ECALL_S => {
            tf.sepc += 4;
        }
        SCAUSE_INST_PAGE_FAULT if tf.sepc == 0 && stval == 0 => {
            if crate::syscall::is_runner_active() {
                crate::syscall::recover_user_fault_to_runner();
            }
            crate::println!(
                "trap: exception scause=0x{:x} stval=0x{:x} sepc=0x{:x}",
                scause,
                stval,
                tf.sepc
            );
            crate::arch::arch_shutdown();
        }
        SCAUSE_LOAD_PAGE_FAULT | SCAUSE_STORE_PAGE_FAULT => {
            if crate::syscall::handle_user_page_fault(stval) {
                return;
            }
            if stval < 0x1000 && crate::syscall::is_runner_active() {
                crate::syscall::recover_user_fault_to_runner();
            }
            crate::println!(
                "trap: exception scause=0x{:x} stval=0x{:x} sepc=0x{:x}",
                scause,
                stval,
                tf.sepc
            );
            crate::arch::arch_shutdown();
        }
        _ => {
            crate::println!(
                "trap: exception scause=0x{:x} stval=0x{:x} sepc=0x{:x}",
                scause,
                stval,
                tf.sepc
            );
            crate::arch::arch_shutdown();
        }
    }
}

#[cfg(target_arch = "loongarch64")]
fn handle_loongarch_trap(tf: &mut TrapFrame, scause: usize, stval: usize) {
    if LA_REAL_ELF_TRACE && crate::syscall::is_runner_active() {
        crate::println!(
            "la-trace: ecode=0x{:x} era=0x{:x} badv=0x{:x} sysno={}",
            scause,
            tf.sepc,
            stval,
            tf.syscall_number(),
        );
    }
    match scause {
        LA_ECODE_SYS => {
            let sysno = tf.syscall_number();
            tf.sepc += 4;
            crate::syscall::syscall(tf);
            if LA_REAL_ELF_TRACE && crate::syscall::is_runner_active() {
                crate::println!("la-trace: sysret no={} ret={}", sysno, tf.arg0());
            }
        }
        LA_ECODE_TLBI | LA_ECODE_PIL | LA_ECODE_PIS | LA_ECODE_PIF | LA_ECODE_PME => {
            if crate::syscall::handle_user_page_fault(stval) {
                return;
            }
            recover_loongarch_user_exception(scause, stval, tf.sepc);
        }
        LA_ECODE_ADE => {
            recover_loongarch_user_exception(scause, stval, tf.sepc);
        }
        _ => {
            recover_loongarch_user_exception(scause, stval, tf.sepc);
        }
    }
}

#[cfg(target_arch = "loongarch64")]
fn recover_loongarch_user_exception(scause: usize, stval: usize, sepc: usize) -> ! {
    if crate::syscall::is_runner_active() {
        crate::syscall::recover_user_fault_to_runner();
    }
    crate::println!(
        "trap: exception scause=0x{:x} stval=0x{:x} sepc=0x{:x}",
        scause,
        stval,
        sepc
    );
    crate::arch::arch_shutdown();
}

// TrapFrame layout must match trap_vector in arch/riscv64.rs
#[repr(C)]
pub struct TrapFrame {
    pub regs: [usize; 32], // x0-x31: 256 bytes (offsets 0-255)
    pub sepc: usize,       // offset 256
    pub sstatus: usize,    // offset 264
    pub scause: usize,     // offset 272
    pub stval: usize,      // offset 280
    pub kernel_sp: usize,  // offset 288
    pub user_satp: usize,  // offset 296
}                          // total: 304 bytes

impl TrapFrame {
    #[cfg(target_arch = "riscv64")]
    pub fn syscall_number(&self) -> usize {
        self.regs[17] // a7
    }

    #[cfg(target_arch = "loongarch64")]
    pub fn syscall_number(&self) -> usize {
        self.regs[11] // a7
    }

    #[cfg(target_arch = "riscv64")]
    pub fn syscall_return(&mut self, value: usize) {
        self.regs[10] = value; // a0
    }

    #[cfg(target_arch = "loongarch64")]
    pub fn syscall_return(&mut self, value: usize) {
        self.regs[4] = value; // a0
    }

    #[cfg(target_arch = "riscv64")]
    pub fn arg0(&self) -> usize { self.regs[10] }
    #[cfg(target_arch = "riscv64")]
    pub fn arg1(&self) -> usize { self.regs[11] }
    #[cfg(target_arch = "riscv64")]
    pub fn arg2(&self) -> usize { self.regs[12] }
    #[cfg(target_arch = "riscv64")]
    pub fn arg3(&self) -> usize { self.regs[13] }
    #[cfg(target_arch = "riscv64")]
    pub fn arg4(&self) -> usize { self.regs[14] }
    #[cfg(target_arch = "riscv64")]
    pub fn arg5(&self) -> usize { self.regs[15] }

    #[cfg(target_arch = "loongarch64")]
    pub fn arg0(&self) -> usize { self.regs[4] }
    #[cfg(target_arch = "loongarch64")]
    pub fn arg1(&self) -> usize { self.regs[5] }
    #[cfg(target_arch = "loongarch64")]
    pub fn arg2(&self) -> usize { self.regs[6] }
    #[cfg(target_arch = "loongarch64")]
    pub fn arg3(&self) -> usize { self.regs[7] }
    #[cfg(target_arch = "loongarch64")]
    pub fn arg4(&self) -> usize { self.regs[8] }
    #[cfg(target_arch = "loongarch64")]
    pub fn arg5(&self) -> usize { self.regs[9] }
}

