const USER_RECLAIM_RANGE_CAP: usize = 32;
const ESRCH: isize = 3;
const EAGAIN: isize = 11;
const EFAULT: isize = 14;
const ECHILD: isize = 10;

struct UserReclaimRanges {
    ranges: [(usize, usize); USER_RECLAIM_RANGE_CAP],
    len: usize,
}

impl UserReclaimRanges {
    const fn new() -> Self {
        Self {
            ranges: [(0, 0); USER_RECLAIM_RANGE_CAP],
            len: 0,
        }
    }

    fn clear(&mut self) {
        self.len = 0;
    }

    fn push(&mut self, start: usize, end: usize) {
        if start < end && self.len < USER_RECLAIM_RANGE_CAP {
            self.ranges[self.len] = (start, end);
            self.len += 1;
        }
    }
}

pub fn write_user_u32(addr: usize, value: u32) -> bool {
    user_write_u32(addr, value)
}

pub fn init_process(kernel_satp: usize) {
    use crate::task::scheduler;
    *KERNEL_SATP.lock() = kernel_satp;
    let ctx = new_process_context();
    *PROCESS_CTX.lock() = Some(ctx.clone());
    scheduler::spawn_init(ctx.fd_table.clone(), kernel_satp);
}

pub fn reset_process_context() {
    use crate::task::scheduler;
    let kernel_satp = *KERNEL_SATP.lock();
    let ctx = new_process_context();
    *PROCESS_CTX.lock() = Some(ctx.clone());
    scheduler::reset_init(ctx.fd_table.clone(), kernel_satp);
}

fn new_process_context() -> Arc<context::ProcessContext> {
    let ctx = Arc::new(context::ProcessContext::new());
    let tty: Arc<dyn crate::fs::vfs::INode> = Arc::new(crate::fs::ramfs::RamFile::new());
    let stdout = FileHandle::console(tty.clone(), 1);
    let stdin = FileHandle::new(tty.clone(), 0);
    let stderr = FileHandle::console(tty, 2);
    ctx.fd_table.alloc(stdin);
    ctx.fd_table.alloc(stdout);
    ctx.fd_table.alloc(stderr);
    ctx
}

pub fn current_context() -> Option<Arc<context::ProcessContext>> {
    PROCESS_CTX.lock().clone()
}

#[cfg(target_arch = "riscv64")]
pub fn debug_last_syscall() -> usize {
    *LAST_SYSCALL.lock()
}

#[cfg(target_arch = "riscv64")]
pub fn debug_fd_present(fd: usize) -> bool {
    let ctx = current_context();
    current_fd_table(&ctx)
        .and_then(|fd_table| fd_table.get(fd))
        .is_some()
}

#[cfg(target_arch = "riscv64")]
pub fn set_trace_basic_case_active(active: bool) {
    *TRACE_BASIC_CASE_ACTIVE.lock() = active;
}

#[cfg(target_arch = "riscv64")]
fn trace_basic_case_active() -> bool {
    RV_SYSCALL_TRACE_CHDIR && *TRACE_BASIC_CASE_ACTIVE.lock()
}

fn current_fd_table(ctx: &Option<Arc<context::ProcessContext>>) -> Option<Arc<FdTable>> {
    crate::task::scheduler::current_process()
        .map(|proc| proc.fd_table.clone())
        .or_else(|| ctx.as_ref().map(|ctx| ctx.fd_table.clone()))
}

