    let sysno = tf.syscall_number();
    *LAST_SYSCALL.lock() = sysno;
    #[cfg(target_arch = "riscv64")]
    if trace_basic_case_active() {
        crate::println!(
            "rv-syscall-trace enter no={} a0=0x{:x} a1=0x{:x} a2=0x{:x} sepc=0x{:x}",
            sysno,
            tf.arg0(),
            tf.arg1(),
            tf.arg2(),
            tf.sepc
        );
    }
    let ctx = current_context();

    let ret = match sysno {
        number::SYS_WRITE => sys_write(
            tf.arg0(), tf.arg1(), tf.arg2(), &ctx,
        ),
        number::SYS_READ => sys_read(
            tf.arg0(), tf.arg1(), tf.arg2(), &ctx,
