static PROCESSES: SpinMutex<Vec<Arc<Process>>> = SpinMutex::new(Vec::new());
static CURRENT: SpinMutex<Option<Arc<Process>>> = SpinMutex::new(None);

// Cooperative scheduler state.
//
// The current model is deliberately single-core and runner-oriented: fork/clone
// queue one child trap frame, then wait/yield/exit performs a controlled switch
// between parent and child. Keep these globals behind scheduler APIs so future
// work can fold them into a SchedulerState struct without changing syscall
// behavior.
pub static PENDING_CHILDREN: SpinMutex<Vec<(Arc<Process>, TrapFrame)>> = SpinMutex::new(Vec::new());
pub static PARENT_TF: SpinMutex<Option<TrapFrame>> = SpinMutex::new(None);
pub static WAIT_STATUS_PTR: SpinMutex<usize> = SpinMutex::new(0);

pub fn spawn_init(fd_table: Arc<FdTable>, satp: usize) -> Arc<Process> {
    let pid = alloc_pid();
    let proc = Arc::new(Process::new(pid, None, fd_table, satp));
    PROCESSES.lock().push(proc.clone());
    *CURRENT.lock() = Some(proc.clone());
    proc
}

pub fn reset_init(fd_table: Arc<FdTable>, satp: usize) -> Arc<Process> {
    PROCESSES.lock().clear();
    reset_case_process_state();
    spawn_init(fd_table, satp)
}

pub fn reset_case_process_state() {
    // Runner case isolation: pending children and saved parent trap frames are
    // test-case local state, not process-global OS state.
    PENDING_CHILDREN.lock().clear();
    *PARENT_TF.lock() = None;
    *WAIT_STATUS_PTR.lock() = 0;
    unsafe { SAVED_PARENT = None; }
}

pub fn current_process() -> Option<Arc<Process>> {
    CURRENT.lock().clone()
}

// Fork: create child with copy of parent's address space.
// child_stack: if Some(sp), set child's user stack pointer (for clone syscall)
pub fn fork_process(parent: &Arc<Process>, parent_tf: &TrapFrame, child_stack: Option<usize>) -> Option<u32> {
    #[cfg(target_arch = "loongarch64")]
    {
        let parent_root = if parent_tf.user_satp == 0 {
            *parent.page_table_root.lock()
        } else {
            parent_tf.user_satp
        };
        let direct_nopaging = parent_tf.user_satp == 0;
        let child_root = if direct_nopaging {
            parent_root
        } else {
            copy_loongarch_user_pages(parent_root)?
        };
        let child_pid = alloc_pid();
        let fd_table = parent.fd_table.fork_clone();
        let child = Arc::new(Process::new(
            child_pid,
            Some(parent.pid),
            fd_table,
            child_root,
        ));
        PROCESSES.lock().push(child.clone());
        parent.children.lock().push(child_pid);

        let mut child_tf = TrapFrame {
            regs: parent_tf.regs,
            sepc: parent_tf.sepc,
            sstatus: parent_tf.sstatus,
            scause: 0,
            stval: 0,
            kernel_sp: parent_tf.kernel_sp,
            user_satp: if direct_nopaging { 0 } else { child_root },
        };
        child_tf.regs[4] = 0; // child fork/clone returns 0 in a0.
        if let Some(sp) = child_stack {
            child_tf.regs[3] = sp; // LoongArch r3 is the stack pointer.
        }
        PENDING_CHILDREN.lock().push((child, child_tf));
        return Some(child_pid);
    }

    #[cfg(target_arch = "riscv64")]
    {
    use crate::memory::pagetable::Sv39PageTable;
    use crate::memory::frame::BumpFrameAllocator;
    use crate::memory::address::PAGE_SIZE;

    let child_pid = alloc_pid();
    let fd_table = parent.fd_table.fork_clone();
    // Use the ACTIVE user page table from the trap frame (not the stored kernel one)
    let parent_satp = parent_tf.user_satp;
    if parent_satp == 0 { return Some(child_pid); } // no user PT, just return PID

    let parent_root_ppn = parent_satp & ((1usize << 44) - 1);
    let parent_root_pa = parent_root_ppn << 12;

    // Create a dummy Sv39PageTable just to access copy_user_pages
    // We need a temporary allocator (won't be used, copy_user_pages uses crate::alloc_page)
    let dummy_pool = crate::alloc_contiguous_pages(4);
    let dummy_alloc = BumpFrameAllocator::new(dummy_pool, 4 * PAGE_SIZE);
    let parent_pt = Sv39PageTable::new(
        crate::memory::address::PhysAddr::new(parent_root_pa),
        dummy_alloc,
    );

    let pt_pool = crate::alloc_contiguous_pages(16);
    let pt_alloc = BumpFrameAllocator::new(pt_pool, 16 * PAGE_SIZE);
    let child_root_pa = parent_pt.copy_user_pages(pt_alloc);
    let child_satp = (8usize << 60) | (child_root_pa.as_usize() >> 12);

    *parent.page_table_root.lock() = parent_satp; // update parent's stored satp
    let child = Arc::new(Process::new(child_pid, Some(parent.pid), fd_table, child_satp));
    PROCESSES.lock().push(child.clone());
    parent.children.lock().push(child_pid);

    let mut child_tf = TrapFrame {
        regs: parent_tf.regs,
        sepc: parent_tf.sepc,
        sstatus: parent_tf.sstatus,
        scause: 0, stval: 0, kernel_sp: parent_tf.kernel_sp,
        user_satp: child_satp, // child's own page table!
    };
    child_tf.regs[10] = 0; // child fork returns 0
    if let Some(sp) = child_stack {
        child_tf.regs[2] = sp; // clone: set child's user stack pointer
    }

    PENDING_CHILDREN.lock().push((child, child_tf));
    Some(child_pid)
    }
}

#[cfg(target_arch = "loongarch64")]
fn copy_loongarch_user_pages(parent_root: usize) -> Option<usize> {
    const ENTRIES: usize = 512;
    const PAGE_SIZE: usize = crate::arch::PAGE_SIZE;
    const PAGE_MASK: usize = !(PAGE_SIZE - 1);
    const PTE_VALID: usize = 1;
    const USER_TOP: usize = 0x4000_0000;

    if parent_root == 0 {
        return None;
    }

    let child_root = crate::alloc_fresh_page().as_usize();
    unsafe {
        (child_root as *mut u8).write_bytes(0, PAGE_SIZE);
    }

    for pgd_idx in 0..ENTRIES {
        let pgd = unsafe { *((parent_root as *const usize).add(pgd_idx)) };
        if pgd & PTE_VALID == 0 {
            continue;
        }
        let pmd_pa = pgd & PAGE_MASK;
        for pmd_idx in 0..ENTRIES {
            let pmd = unsafe { *((pmd_pa as *const usize).add(pmd_idx)) };
            if pmd & PTE_VALID == 0 {
                continue;
            }
            let pte_pa = pmd & PAGE_MASK;
            for pte_idx in 0..ENTRIES {
                let pte = unsafe { *((pte_pa as *const usize).add(pte_idx)) };
                if pte & PTE_VALID == 0 {
                    continue;
                }
                let va = (pgd_idx << 30) | (pmd_idx << 21) | (pte_idx << 12);
                if va >= USER_TOP {
                    continue;
                }
                let src_pa = pte & PAGE_MASK;
                let dst_pa = crate::alloc_fresh_page().as_usize();
                unsafe {
                    core::ptr::copy_nonoverlapping(
                        src_pa as *const u8,
                        dst_pa as *mut u8,
                        PAGE_SIZE,
                    );
                }
                crate::arch::map_page(child_root, va, dst_pa, pte & (PAGE_SIZE - 1));
            }
        }
    }

    Some(child_root)
}

#[cfg(target_arch = "loongarch64")]
pub fn spawn_exited_child(parent: &Arc<Process>, exit_code: usize) -> u32 {
    let child_pid = alloc_pid();
    let fd_table = parent.fd_table.fork_clone();
    let child = Arc::new(Process::new(
        child_pid,
        Some(parent.pid),
        fd_table,
        *parent.page_table_root.lock(),
    ));
    *child.state.lock() = ProcessState::Zombie(exit_code);
    PROCESSES.lock().push(child);
    parent.children.lock().push(child_pid);
    child_pid
}

