pub fn exit_process(exit_code: usize) -> ! {
    let child_pid;
    if let Some(ref p) = current_process() {
        child_pid = p.pid;
        *p.state.lock() = ProcessState::Zombie(exit_code);
    } else {
        child_pid = 0;
    }
    // Take parent context, dropping lock before noreturn
    let parent_opt = PARENT_TF.lock().take();
    if let Some(mut parent_tf) = parent_opt {
        #[cfg(target_arch = "riscv64")]
        unsafe {
            core::arch::asm!(
                "csrw satp, {satp}",
                "sfence.vma",
                satp = in(reg) parent_tf.user_satp,
                options(nostack),
            );
        }
        let status_ptr = *WAIT_STATUS_PTR.lock();
        if status_ptr != 0 {
            let _ = crate::syscall::write_user_u32(status_ptr, (exit_code as u32) << 8);
        }
        #[cfg(target_arch = "riscv64")]
        {
            parent_tf.regs[10] = child_pid as usize;
        }
        #[cfg(target_arch = "loongarch64")]
        {
            parent_tf.regs[4] = child_pid as usize;
        }
        unsafe {
            if let Some(ref parent_proc) = SAVED_PARENT {
                let mut children = parent_proc.children.lock();
                if let Some(pos) = children.iter().position(|pid| *pid == child_pid) {
                    children.remove(pos);
                }
                *CURRENT.lock() = Some(parent_proc.clone());
            }
        }
        unsafe { switch_to_parent(&parent_tf); }
    }
    crate::arch::arch_shutdown();
}

#[cfg(target_arch = "riscv64")]
unsafe fn switch_to_parent(tf: &TrapFrame) -> ! {
    let p = tf as *const _ as usize;
    core::arch::asm!(
        "mv sp, {0}", "csrw sscratch, {0}", "j trap_return",
        in(reg) p, options(noreturn),
    );
}
#[cfg(not(target_arch = "riscv64"))]
unsafe fn switch_to_parent(tf: &TrapFrame) -> ! {
    #[cfg(target_arch = "loongarch64")]
    {
        let p = tf as *const _ as usize;
        core::arch::asm!(
            "ori $sp, {0}, 0",
            "b trap_return",
            in(reg) p,
            options(noreturn),
        );
    }
    #[cfg(not(target_arch = "loongarch64"))]
    {
        let _ = tf;
        crate::arch::arch_shutdown();
    }
}

// Try to run a pending child (called from wait4)
pub fn try_run_child(parent_tf: &TrapFrame) -> bool {
    let pending = {
        let mut children = PENDING_CHILDREN.lock();
        if children.is_empty() {
            None
        } else {
            Some(children.remove(0))
        }
    };
    if let Some((child, child_tf)) = pending {
        // Save parent process for restoration
        let parent_proc = current_process();
        // Save parent's trap frame
        *PARENT_TF.lock() = Some(TrapFrame {
            regs: parent_tf.regs,
            sepc: parent_tf.sepc,
            sstatus: parent_tf.sstatus,
            scause: 0, stval: 0, kernel_sp: parent_tf.kernel_sp,
            user_satp: parent_tf.user_satp,
        });
        // Switch to child
        let cpid = child.pid;
        let csepc = child_tf.sepc;
        *CURRENT.lock() = Some(child.clone());
        // Save parent process reference in a global for restoration
        unsafe { SAVED_PARENT = parent_proc; }
        let _ = (cpid, csepc);
        #[cfg(target_arch = "riscv64")]
        {
            let p = &child_tf as *const _ as usize;
            unsafe {
                core::arch::asm!(
                    "mv sp, {0}", "csrw sscratch, {0}", "j trap_return",
                    in(reg) p, options(noreturn),
                );
            }
        }
        #[cfg(not(target_arch = "riscv64"))]
        {
            #[cfg(target_arch = "loongarch64")]
            {
                if child_tf.user_satp == 0 {
                    crate::arch::setup_user_direct_dmw();
                    crate::arch::disable_paging();
                } else {
                    crate::arch::setup_user_pt(child_tf.user_satp);
                    crate::arch::prefill_tlb_pair(child_tf.user_satp, child_tf.sepc);
                    crate::arch::prefill_tlb_pair(child_tf.user_satp, child_tf.regs[3]);
                }
                let p = &child_tf as *const _ as usize;
                unsafe {
                    core::arch::asm!(
                        "ori $sp, {0}, 0",
                        "b trap_return",
                        in(reg) p,
                        options(noreturn),
                    );
                }
            }
            #[cfg(not(target_arch = "loongarch64"))]
            {
                crate::arch::arch_shutdown();
            }
        }
    }
    false
}

static mut SAVED_PARENT: Option<Arc<Process>> = None;

pub fn wait_for_child(wait_pid: i32) -> Option<(u32, usize)> {
    let proc = current_process()?;
    let mut children = proc.children.lock();
    for idx in 0..children.len() {
        let cpid = children[idx];
        let procs = PROCESSES.lock();
        if let Some(child) = procs.iter().find(|p| p.pid == cpid) {
            let state = *child.state.lock();
            if let ProcessState::Zombie(code) = state {
                if wait_pid == -1 || wait_pid == cpid as i32 {
                    children.remove(idx);
                    return Some((cpid, code));
                }
            }
        }
    }
    None
}

