use crate::memory::address::{PhysAddr, PAGE_SIZE};

pub struct BumpFrameAllocator {
    next: usize,
    end: usize,
    allocated: usize,
}

impl BumpFrameAllocator {
    pub fn new(mem_start: PhysAddr, mem_size: usize) -> Self {
        let start = mem_start.align_up().as_usize();
        let end = start + (mem_size & !(PAGE_SIZE - 1));
        BumpFrameAllocator {
            next: start,
            end,
            allocated: 0,
        }
    }

    pub fn alloc(&mut self) -> Option<PhysAddr> {
        if self.next >= self.end {
            return None;
        }
        let addr = PhysAddr::new(self.next);
        self.next += PAGE_SIZE;
        self.allocated += 1;
        Some(addr)
    }

    pub fn alloc_contiguous(&mut self, pages: usize) -> Option<PhysAddr> {
        let size = pages * PAGE_SIZE;
        if self.next + size > self.end {
            return None;
        }
        let addr = PhysAddr::new(self.next);
        self.next += size;
        self.allocated += pages;
        Some(addr)
    }

    pub fn allocated_pages(&self) -> usize {
        self.allocated
    }

    pub fn remaining_pages(&self) -> usize {
        (self.end - self.next) / PAGE_SIZE
    }
}

