const MIN_BLOCK_SIZE: usize = core::mem::size_of::<usize>() * 2;

fn align_up_to(addr: usize, align: usize) -> usize {
    let mask = align - 1;
    (addr + mask) & !mask
}

pub struct SimpleHeap {
    head: *mut usize, // pointer to first free block (block starts with size field)
    heap_start: usize,
    heap_size: usize,
    used: usize,
    next: usize,
}

unsafe impl Send for SimpleHeap {}

impl SimpleHeap {
    pub const fn empty() -> Self {
        SimpleHeap {
            head: ptr::null_mut(),
            heap_start: 0,
            heap_size: 0,
            used: 0,
            next: 0,
        }
    }

    pub unsafe fn init(&mut self, start: usize, size: usize) {
        self.heap_start = start;
        self.heap_size = size;
        self.used = 0;
        self.next = start;
        self.head = ptr::null_mut();
    }

    pub fn used_bytes(&self) -> usize {
        self.used
    }
}

pub struct LockedHeap(pub SpinMutex<SimpleHeap>);

impl LockedHeap {
    pub const fn empty() -> Self {
        LockedHeap(SpinMutex::new(SimpleHeap::empty()))
    }
}

unsafe impl GlobalAlloc for LockedHeap {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let mut heap = self.0.lock();
        let raw_align = layout.align();
        let align = if raw_align.is_power_of_two() && raw_align <= 4096 {
            raw_align.max(core::mem::align_of::<usize>())
        } else {
            core::mem::align_of::<usize>()
        };
        let size = align_up_to(layout.size().max(MIN_BLOCK_SIZE), align);

        let alloc_start = align_up_to(heap.next, align);
        let alloc_end = alloc_start.saturating_add(size);
        let heap_end = heap.heap_start.saturating_add(heap.heap_size);
        if alloc_end <= heap_end {
            heap.next = alloc_end;
            heap.used = heap.next.saturating_sub(heap.heap_start);
            return alloc_start as *mut u8;
        }

        ptr::null_mut()
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        let mut heap = self.0.lock();
        let size = align_up_to(layout.size().max(MIN_BLOCK_SIZE), core::mem::align_of::<usize>());
        heap.used = heap.used.saturating_sub(size);
        let _ = ptr;
    }
}

