pub trait PageTable {
    fn map(&mut self, vaddr: VirtAddr, paddr: PhysAddr, flags: PteFlags);
    fn unmap(&mut self, vaddr: VirtAddr);
    fn translate(&self, vaddr: VirtAddr) -> Option<PhysAddr>;
    fn activate(&self);
}

const PTE_VALID: usize = 1 << 0;
const PTE_READ: usize = 1 << 1;
const PTE_WRITE: usize = 1 << 2;
const PTE_EXEC: usize = 1 << 3;
const PTE_USER: usize = 1 << 4;
const PTE_GLOBAL: usize = 1 << 5;
const PTE_ACCESS: usize = 1 << 6;
const PTE_DIRTY: usize = 1 << 7;

fn flags_to_sv39(flags: PteFlags) -> usize {
    let mut pte = PTE_VALID | PTE_ACCESS | PTE_DIRTY;
    if flags.contains(PteFlags::READ) {
        pte |= PTE_READ;
    }
    if flags.contains(PteFlags::WRITE) {
        pte |= PTE_WRITE;
    }
    if flags.contains(PteFlags::EXECUTE) {
        pte |= PTE_EXEC;
    }
    if flags.contains(PteFlags::USER) {
        pte |= PTE_USER;
    }
    if flags.contains(PteFlags::GLOBAL) {
        pte |= PTE_GLOBAL;
    }
    pte
}

const SV39_LEVELS: usize = 3;
const SV39_ENTRIES: usize = 512;

fn sv39_vpn(vaddr: VirtAddr, level: usize) -> usize {
    let shift = 12 + 9 * level;
    (vaddr.as_usize() >> shift) & 0x1FF
}

pub struct Sv39PageTable {
    root_paddr: PhysAddr,
    allocator: BumpFrameAllocator,
}

impl Sv39PageTable {
    pub fn new(root_paddr: PhysAddr, allocator: BumpFrameAllocator) -> Self {
        Sv39PageTable { root_paddr, allocator }
    }

    pub fn root_paddr(&self) -> PhysAddr { self.root_paddr }

    fn alloc_page(&mut self) -> Option<PhysAddr> {
        self.allocator.alloc().or_else(|| Some(crate::alloc_page()))
    }

    pub fn unmap_leaf(&mut self, vaddr: VirtAddr) -> Option<PhysAddr> {
        let mut paddr = self.root_paddr;
        for level in (0..SV39_LEVELS).rev() {
            let vpn = sv39_vpn(vaddr, level);
            let table = unsafe { &mut *(paddr.as_usize() as *mut [usize; SV39_ENTRIES]) };
            let entry = table[vpn];
            if entry & PTE_VALID == 0 {
                return None;
            }
            if level == 0 {
                table[vpn] = 0;
                return Some(PhysAddr::new((entry >> 10) << 12));
            }
            paddr = PhysAddr::new((entry >> 10) << 12);
        }
        None
    }

    // Copy all USER-mapped pages to a new page table.
    // Returns the new root PhysAddr.
    pub fn copy_user_pages(&self, new_allocator: BumpFrameAllocator) -> PhysAddr {
        let new_root_pa = crate::alloc_page();
        unsafe { (new_root_pa.as_usize() as *mut u8).write_bytes(0, PAGE_SIZE); }
        let mut new_pt = Sv39PageTable::new(new_root_pa, new_allocator);
        self.copy_level(new_root_pa.as_usize(), self.root_paddr.as_usize(), 2);
        new_root_pa
    }

    fn copy_level(&self, new_table_pa: usize, old_table_pa: usize, level: usize) {
        // Safety: only access identity-mapped physical addresses
        if old_table_pa == 0 || old_table_pa < 0x80000000 {
            crate::println!("copy_level: bad old_table_pa=0x{:x} level={}", old_table_pa, level);
            return;
        }
        let old = unsafe { &*(old_table_pa as *const [usize; SV39_ENTRIES]) };
        let new_tbl = unsafe { &mut *(new_table_pa as *mut [usize; SV39_ENTRIES]) };

        for i in 0..SV39_ENTRIES {
            let entry = old[i];
            if entry & PTE_VALID == 0 { continue; }

            if level == 0 {
                if entry & PTE_USER != 0 {
                    let old_pa = (entry >> 10) << 12;
                    if old_pa < 0x80000000 { continue; } // skip invalid
                    let new_pa = crate::alloc_page().as_usize();
                    unsafe {
                        core::ptr::copy_nonoverlapping(
                            old_pa as *const u8,
                            new_pa as *mut u8,
                            PAGE_SIZE,
                        );
                    }
                    let flags = entry & 0x3FF;
                    new_tbl[i] = (new_pa >> 2) | flags;
                }
            } else {
                // Non-leaf: share kernel mappings, copy user mappings
                let va_base = i << (12 + 9 * level);
                let is_kernel = va_base >= 0x80000000;
                if is_kernel {
                    // Share kernel page table pages
                    new_tbl[i] = entry;
                } else {
                    let old_child_pa = (entry >> 10) << 12;
                    if old_child_pa < 0x80000000 { continue; }
                    let new_child_pa = crate::alloc_page().as_usize();
                    unsafe { (new_child_pa as *mut u8).write_bytes(0, PAGE_SIZE); }
                    let flags = entry & 0x3FF;
                    new_tbl[i] = (new_child_pa >> 2) | flags;
                    self.copy_level(new_child_pa, old_child_pa, level - 1);
                }
            }
        }
    }

    fn walk_create(&mut self, vaddr: VirtAddr) -> &mut usize {
        let mut paddr = self.root_paddr;
        for level in (0..SV39_LEVELS).rev() {
            let vpn = sv39_vpn(vaddr, level);
            let table = unsafe { &mut *(paddr.as_usize() as *mut [usize; SV39_ENTRIES]) };
            if level == 0 {
                return &mut table[vpn];
            }
            let entry = table[vpn];
            if entry & PTE_VALID == 0 {
                let new_page = self.alloc_page().expect("OOM: page table page");
                let new_table =
                    unsafe { &mut *(new_page.as_usize() as *mut [usize; SV39_ENTRIES]) };
                *new_table = [0; SV39_ENTRIES];
                table[vpn] = (new_page.as_usize() >> 2) | PTE_VALID;
                paddr = new_page;
            } else {
                paddr = PhysAddr::new((entry >> 10) << 12);
            }
        }
        unreachable!()
    }
}

