}

impl FileType {
    pub fn from_mode(mode: u16) -> Self {
        match mode & 0xF000 {
            0x4000 => FileType::Directory,
            0x2000 => FileType::CharDevice,
            0x6000 => FileType::BlockDevice,
            _ => FileType::File,
        }
    }
}

pub enum SeekFrom {
    Start(u64),
    Current(i64),
    End(i64),
}

pub trait INode: Send + Sync {
    fn file_type(&self) -> FileType;
    fn stat(&self) -> FileStat;
    fn read_at(&self, offset: usize, buf: &mut [u8]) -> usize;
    fn write_at(&self, offset: usize, buf: &[u8]) -> usize;
    fn truncate(&self, _size: usize) -> bool { false }
    fn mkdir(&self, _name: &str) -> bool { false }
    fn add_child(&self, _name: &str, _node: Arc<dyn INode>) -> bool { false }
    fn lookup(&self, _name: &str) -> Option<Arc<dyn INode>> { None }
    fn read_dir(&self) -> Vec<String> { Vec::new() }
    fn unlink(&self, _name: &str) -> bool { false }
    fn rename(&self, _old_name: &str, _new_name: &str) -> bool { false }
}

pub struct FileHandle {
    pub inode: Arc<dyn INode>,
    pub offset: usize,
    pub flags: u32,
    pub console: bool,
}

impl FileHandle {
    pub fn new(inode: Arc<dyn INode>, flags: u32) -> Self {
        FileHandle { inode, offset: 0, flags, console: false }
    }

    pub fn console(inode: Arc<dyn INode>, flags: u32) -> Self {
        FileHandle { inode, offset: 0, flags, console: true }
    }

    pub fn read(&mut self, buf: &mut [u8]) -> usize {
        let n = self.inode.read_at(self.offset, buf);
        self.offset += n;
        n
    }

    pub fn write(&mut self, buf: &[u8]) -> usize {
        let n = self.inode.write_at(self.offset, buf);
        self.offset += n;
        n
    }

    pub fn seek(&mut self, pos: SeekFrom) -> usize {
        let size = self.inode.stat().size as usize;
        self.offset = match pos {
            SeekFrom::Start(o) => o as usize,
            SeekFrom::Current(d) => ((self.offset as i64) + d).max(0) as usize,
            SeekFrom::End(d) => ((size as i64) + d).max(0) as usize,
        };
        self.offset
    }
}

