use alloc::string::String;
use alloc::vec::Vec;
use alloc::sync::Arc;
use crate::sync::SpinMutex;
use crate::fs::vfs::{FileStat, FileType, INode};

pub struct RamFile {
    data: SpinMutex<Vec<u8>>,
}

impl RamFile {
    pub fn new() -> Self { RamFile { data: SpinMutex::new(Vec::new()) } }
    pub fn from_bytes(b: &[u8]) -> Self {
        RamFile { data: SpinMutex::new(Vec::from(b)) }
    }
}

impl INode for RamFile {
    fn file_type(&self) -> FileType { FileType::File }
    fn stat(&self) -> FileStat {
        FileStat { ino: 0, size: self.data.lock().len() as u64, mode: 0x8000, nlink: 1 }
    }
    fn read_at(&self, offset: usize, buf: &mut [u8]) -> usize {
        let d = self.data.lock();
        if offset >= d.len() { return 0; }
        let n = buf.len().min(d.len() - offset);
        buf[..n].copy_from_slice(&d[offset..offset + n]);
        n
    }
    fn write_at(&self, offset: usize, buf: &[u8]) -> usize {
        let mut d = self.data.lock();
        if offset + buf.len() > d.len() { d.resize(offset + buf.len(), 0); }
        d[offset..offset + buf.len()].copy_from_slice(buf);
        buf.len()
    }
    fn truncate(&self, size: usize) -> bool {
        self.data.lock().resize(size, 0);
        true
    }
}

struct DirItem {
    name: String,
    node: Arc<dyn INode>,
}

pub struct RamDir {
    items: SpinMutex<Vec<DirItem>>,
}

impl RamDir {
    pub fn new() -> Self { RamDir { items: SpinMutex::new(Vec::new()) } }

    pub fn add(&self, name: &str, node: Arc<dyn INode>) {
        let mut items = self.items.lock();
        if let Some(item) = items.iter_mut().find(|item| item.name == name) {
            item.node = node;
            return;
        }
        items.push(DirItem { name: String::from(name), node });
    }
}

impl INode for RamDir {
    fn file_type(&self) -> FileType { FileType::Directory }
    fn stat(&self) -> FileStat {
        FileStat { ino: 0, size: 4096, mode: 0x4000, nlink: 1 }
    }
    fn read_at(&self, _o: usize, _b: &mut [u8]) -> usize { 0 }
    fn write_at(&self, _o: usize, _b: &[u8]) -> usize { 0 }
    fn mkdir(&self, name: &str) -> bool {
        let items = self.items.lock();
        if items.iter().any(|d| d.name == name) { return false; }
        drop(items);
        let dir = Arc::new(RamDir::new());
        self.add(name, dir);
        true
    }
    fn add_child(&self, name: &str, node: Arc<dyn INode>) -> bool {
        self.add(name, node);
        true
    }
    fn lookup(&self, name: &str) -> Option<Arc<dyn INode>> {
        self.items.lock().iter().find(|d| d.name == name).map(|d| d.node.clone())
    }
    fn read_dir(&self) -> Vec<String> {
        self.items.lock().iter().map(|d| d.name.clone()).collect()
    }
    fn unlink(&self, name: &str) -> bool {
        let mut items = self.items.lock();
        if let Some(p) = items.iter().position(|d| d.name == name) {
            items.remove(p);
            true
        } else { false }
    }
    fn rename(&self, old_name: &str, new_name: &str) -> bool {
        if old_name == new_name {
            return self.lookup(old_name).is_some();
        }
        let mut items = self.items.lock();
        let Some(old_pos) = items.iter().position(|d| d.name == old_name) else {
            return false;
        };
        if let Some(new_pos) = items.iter().position(|d| d.name == new_name) {
            items.remove(new_pos);
            let old_pos = if new_pos < old_pos { old_pos - 1 } else { old_pos };
            items[old_pos].name = String::from(new_name);
        } else {
            items[old_pos].name = String::from(new_name);
        }
        true
    }
}

