    group_desc_table_block: u64,
    inodes_per_group: u32,
}

impl Ext4Fs {
    pub fn open(mut blk: VirtIoBlk) -> Option<Self> {
        let mut buf = [0u8; 512];
        if !blk.read_sector(2, &mut buf) {
            crate::println!("ext4: read failed");
            return None;
        }
        let magic = u16::from_le_bytes([buf[0x38], buf[0x39]]);
        crate::println!("ext4: magic=0x{:04x}", magic);
        if magic != EXT4_MAGIC {
            return None;
        }
        let log_block_size: u32 = unsafe { *(buf.as_ptr().add(0x18) as *const u32) };
        let block_size: usize = 1024 << log_block_size as usize;

        let ipg: u32 = unsafe { *(buf.as_ptr().add(0x28) as *const u32) };
        let gdt_block = if block_size == 1024 { 2u64 } else { 1u64 };
        crate::println!("ext4: blksz={} ipg={}", block_size, ipg);
        Some(Ext4Fs { blk, block_size, group_desc_table_block: gdt_block, inodes_per_group: ipg })
    }

    fn read_block(&mut self, block: u64, buf: &mut [u8]) -> bool {
        let spb = self.block_size / SECTOR_SIZE;
        for i in 0..spb {
            let mut sec = [0u8; SECTOR_SIZE];
            if !BlockDevice::read_sector(&mut self.blk, block * spb as u64 + i as u64, &mut sec) {
                return false;
            }
            buf[i * SECTOR_SIZE..(i + 1) * SECTOR_SIZE].copy_from_slice(&sec);
        }
        true
    }

    pub fn read_inode(&mut self, inode_num: u32) -> Option<Inode> {
        let group = (inode_num - 1) / self.inodes_per_group;
        let index = (inode_num - 1) % self.inodes_per_group;

        let gdt_off = group as u64 * 64;
        let gdt_block = self.group_desc_table_block + gdt_off / self.block_size as u64;
        let gdt_boff = gdt_off % self.block_size as u64;

        let mut buf = alloc_buf(self.block_size);
        if !self.read_block(gdt_block, &mut buf) {
            return None;
        }

        let bgd = unsafe { &*(buf.as_ptr().add(gdt_boff as usize) as *const BgDescriptor) };
        let inode_table = bgd.inode_table_lo as u64 | ((bgd.inode_table_high as u64) << 32);

        let isize = 256u64;
        let ioff = index as u64 * isize;
        let iblock = inode_table + ioff / self.block_size as u64;
        let iboff = ioff % self.block_size as u64;

        if !self.read_block(iblock, &mut buf) {
            return None;
        }

        let mut inode = Inode::zeroed();
        unsafe {
            core::ptr::copy_nonoverlapping(
                buf.as_ptr().add(iboff as usize) as *const Inode,
                &mut inode as *mut Inode,
                1,
            );
        }
        Some(inode)
    }

    fn extent_lookup(&mut self, inode: &Inode, target: u32) -> Option<u64> {
        let hdr = unsafe { &*(inode.block.as_ptr() as *const ExtentHeader) };
        if hdr.magic != 0xF30A {
            return None;
        }

        if hdr.depth == 0 {
