            for _ in 0..hdr.entries {
                let ex = unsafe { &*ptr };
                if target >= ex.block && target < ex.block + ex.len as u32 {
                    let start = ex.start_lo as u64 | ((ex.start_hi as u64) << 32);
                    return Some(start + (target - ex.block) as u64);
                }
                ptr = ptr.wrapping_add(1);
