// Static ELF loader for RISC-V64

use crate::memory::address::{PhysAddr, VirtAddr, PAGE_SIZE};

pub const ELF_MAGIC: [u8; 4] = [0x7f, b'E', b'L', b'F'];

const EM_RISCV: u16 = 243;
const EM_LOONGARCH: u16 = 258;

const ET_EXEC: u16 = 2;
const ET_DYN: u16 = 3;
const PT_LOAD: u32 = 1;

#[repr(C)]
pub struct ElfHeader {
    pub magic: [u8; 4],
    pub class: u8,
    pub encoding: u8,
    pub version: u8,
    pub _pad: [u8; 9],
    pub elf_type: u16,
    pub machine: u16,
    pub version2: u32,
    pub entry: u64,
    pub phoff: u64,
    pub shoff: u64,
    pub flags: u32,
    pub ehsize: u16,
    pub phentsize: u16,
    pub phnum: u16,
    pub shentsize: u16,
    pub shnum: u16,
    pub shstrndx: u16,
}

#[repr(C)]
pub struct ProgramHeader {
    pub p_type: u32,
    pub p_flags: u32,
    pub p_offset: u64,
    pub p_vaddr: u64,
    pub p_paddr: u64,
    pub p_filesz: u64,
    pub p_memsz: u64,
    pub p_align: u64,
}

pub struct LoadedElf {
    pub entry: VirtAddr,
    pub segments: usize,
    pub is_pie: bool,  // ET_DYN (Position-Independent Executable)
}

pub fn parse_elf(data: &[u8]) -> Result<LoadedElf, &'static str> {
    if data.len() < core::mem::size_of::<ElfHeader>() {
        return Err("ELF too small");
    }

    let header = unsafe { &*(data.as_ptr() as *const ElfHeader) };

    if header.magic != ELF_MAGIC {
        return Err("bad magic");
    }
    if header.class != 2 {
        return Err("not 64-bit");
    }
    if header.encoding != 1 {
        return Err("not little-endian");
    }
    if header.elf_type != ET_EXEC && header.elf_type != ET_DYN {
        return Err("not executable");
    }

    #[cfg(target_arch = "riscv64")]
    if header.machine != EM_RISCV {
        return Err("not RISC-V");
    }
    #[cfg(target_arch = "loongarch64")]
    if header.machine != EM_LOONGARCH {
        return Err("not LoongArch");
    }

    Ok(LoadedElf {
        entry: VirtAddr::new(header.entry as usize),
        segments: header.phnum as usize,
        is_pie: header.elf_type == ET_DYN,
    })
}

pub fn program_header_vaddr(data: &[u8], pie_base: usize) -> usize {
    let header = unsafe { &*(data.as_ptr() as *const ElfHeader) };
    let ph_size = core::mem::size_of::<ProgramHeader>();
    let phoff = header.phoff as usize;

    for i in 0..header.phnum as usize {
        let ph = unsafe {
            &*(data.as_ptr().add(phoff + i * ph_size) as *const ProgramHeader)
        };

        if ph.p_type != PT_LOAD {
            continue;
        }

        let start = ph.p_offset as usize;
        let end = start.saturating_add(ph.p_filesz as usize);
        if phoff >= start && phoff < end {
            return pie_base + ph.p_vaddr as usize + (phoff - start);
        }
    }

    pie_base + phoff
}

pub fn load_elf_segments(
    data: &[u8],
    user_page_map: &mut dyn FnMut(VirtAddr, &[u8], usize, u32),
) -> Result<LoadedElf, &'static str> {
    let header = unsafe { &*(data.as_ptr() as *const ElfHeader) };

    let loaded = parse_elf(data)?;

    let ph_size = core::mem::size_of::<ProgramHeader>();
    let ph_start = header.phoff as usize;

    for i in 0..header.phnum as usize {
        let ph = unsafe {
            &*(data.as_ptr().add(ph_start + i * ph_size) as *const ProgramHeader)
        };

        if ph.p_type != PT_LOAD {
            continue;
        }

        let file_data = if ph.p_filesz > 0 {
            let start = ph.p_offset as usize;
            let end = start + ph.p_filesz as usize;
            if end > data.len() {
                return Err("segment data out of bounds");
            }
            &data[start..end]
        } else {
            &[]
        };

        user_page_map(
            VirtAddr::new(ph.p_vaddr as usize),
            file_data,
            ph.p_memsz as usize,
            ph.p_flags,
        );
    }

    Ok(loaded)
}

