// Write: fd=1/2 → console output
fn sys_write(fd: usize, buf: usize, len: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if fd == 1 || fd == 2 {
        let mut written = 0;
        while written < len {
            let Some(byte) = user_read_byte(buf + written) else {
                break;
            };
            crate::arch::putchar(byte);
            written += 1;
        }
        return len;
    }
    if let Some(fd_table) = current_fd_table(_ctx) {
        if let Some(fh) = fd_table.get(fd) {
            let mut fh = fh.lock();
            if fh.console {
                let mut written = 0;
                while written < len {
                    let Some(byte) = user_read_byte(buf + written) else {
                        break;
                    };
                    crate::arch::putchar(byte);
                    written += 1;
                }
                return len;
            }
            let mut data = Vec::new();
            data.resize(len, 0);
            if !user_read_bytes(buf, data.as_mut_slice()) {
                return (-14isize) as usize;
            }
            if fh.flags & 0x400 != 0 {
                fh.offset = fh.inode.stat().size as usize;
            }
            let n = fh.inode.write_at(fh.offset, data.as_slice());
            fh.offset += n;
            return n;
        }
    }
    0
}

fn sys_read(fd: usize, buf: usize, len: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if fd == 0 {
        // stdin returns 0 (EOF) for now
        return 0;
    }
    if let Some(fd_table) = current_fd_table(_ctx) {
        if let Some(fh) = fd_table.get(fd) {
            let mut fh = fh.lock();
            let mut total = 0;
            while total < len {
                let mut byte = [0u8; 1];
                let b = fh.inode.read_at(fh.offset + total, &mut byte);
                if b == 0 { break; }
                if !user_write_bytes(buf + total, &byte[..b]) {
                    return (-14isize) as usize;
                }
                total += b;
            }
            fh.offset += total;
            return total;
        }
    }
    0
}

fn sys_openat(_dirfd: usize, path_ptr: usize, flags: usize, _mode: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let (Some(ref ctx), Some(fd_table)) = (_ctx, current_fd_table(_ctx)) {
        let path = unsafe { read_user_str(path_ptr) };
        const O_CREAT: usize = 0x40;
        const O_TRUNC: usize = 0x200;
        let inode = match ctx.lookup(&path) {
            Some(inode) => inode,
            None if flags & O_CREAT != 0 => {
                match ctx.create_file(&path) {
                    Some(inode) => inode,
                    None => return (-2isize) as usize,
                }
            }
            None => return (-2isize) as usize,
        };
        if flags & O_TRUNC != 0 {
            let _ = inode.truncate(0);
        }
        let fh = FileHandle::new(inode, flags as u32);
        return fd_table.alloc(fh);
    }
    (-1isize) as usize
}

fn sys_unlinkat(_dirfd: usize, path_ptr: usize, _flags: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let Some(ref ctx) = _ctx {
        let path = unsafe { read_user_str(path_ptr) };
        return if ctx.unlink(&path) { 0 } else { (-2isize) as usize };
    }
    (-1isize) as usize
}

fn sys_renameat(old_path_ptr: usize, new_path_ptr: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let Some(ref ctx) = _ctx {
        let old_path = unsafe { read_user_str(old_path_ptr) };
        let new_path = unsafe { read_user_str(new_path_ptr) };
        return if ctx.rename(&old_path, &new_path) { 0 } else { (-2isize) as usize };
    }
    (-1isize) as usize
}

fn sys_close(fd: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let Some(fd_table) = current_fd_table(_ctx) {
        if fd_table.close(fd) { return 0; }
    }
    (-1isize) as usize
}

fn sys_fstat(fd: usize, buf: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let Some(fd_table) = current_fd_table(_ctx) {
        if let Some(fh) = fd_table.get(fd) {
            let fh = fh.lock();
            write_kstat(buf, &fh.inode.stat());
            return 0;
        }
    }
    (-1isize) as usize
}

fn sys_fstatat(path_ptr: usize, buf: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    if let Some(ref ctx) = _ctx {
        let path = unsafe { read_user_str(path_ptr) };
        if let Some(inode) = ctx.lookup(&path) {
            write_kstat(buf, &inode.stat());
            return 0;
        }
    }
    (-2isize) as usize
}

fn write_kstat(buf: usize, stat: &FileStat) {
    // Linux/RISC-V kstat layout used by the contest libc:
    // u64 dev, ino; u32 mode, nlink, uid, gid; u64 rdev, pad, size; ...
    let _ = user_write_u64(buf, 0);
    let _ = user_write_u64(buf + 8, stat.ino);
    let _ = user_write_u32(buf + 16, stat.mode as u32);
    let _ = user_write_u32(buf + 20, stat.nlink);
    let _ = user_write_u32(buf + 24, 0);
    let _ = user_write_u32(buf + 28, 0);
    let _ = user_write_u64(buf + 32, 0);

