#[cfg(target_arch = "riscv64")]
fn user_program_bytes() -> [u8; 64] {
    // RISC-V64 LE: write(1, msg@0x2000, 6); exit(0)
    let words: [u32; 9] = [
        0x04000893, // addi a7, x0, 64
        0x00100513, // addi a0, x0, 1
        0x000025b7, // lui a1, 0x2
        0x00058593, // addi a1, a1, 0
        0x00600613, // addi a2, x0, 6
        0x00000073, // ecall
        0x05d00893, // addi a7, x0, 93
        0x00000513, // addi a0, x0, 0
        0x00000073, // ecall
    ];
    let mut bytes = [0u8; 64];
    for (i, w) in words.iter().enumerate() {
        let b = w.to_le_bytes();
        bytes[i*4..i*4+4].copy_from_slice(&b);
    }
    bytes
}

// Helpers (public for runner module)
pub fn alloc_page() -> PhysAddr {
    if let Some(page) = RECYCLED_USER_PAGES.lock().pop() {
        return PhysAddr::new(page);
    }
    alloc_fresh_page()
}

pub fn alloc_fresh_page() -> PhysAddr {
    let mut fa = FRAME_ALLOCATOR.lock();
    fa.as_mut().unwrap().alloc().expect("OOM")
}

pub fn recycle_user_page(page: PhysAddr) {
    RECYCLED_USER_PAGES.lock().push(page.as_usize());
}

pub fn alloc_contiguous_pages(n: usize) -> PhysAddr {
    let mut fa = FRAME_ALLOCATOR.lock();
    fa.as_mut().unwrap().alloc_contiguous(n).expect("OOM")
}

fn va(a: usize) -> VirtAddr { VirtAddr::new(a) }
fn pa(a: usize) -> PhysAddr { PhysAddr::new(a) }

#[cfg(target_arch = "loongarch64")]
fn test_la_paging() {
    use crate::arch::{map_page, la_pte, PAGE_SIZE};
    for &b in b"[alloc]\n" { crate::arch::putchar(b); }
    // Allocate root page table from frame allocator
    let root_pa = alloc_page().as_usize();
    for &b in b"[root ok]\n" { crate::arch::putchar(b); }
    unsafe { (root_pa as *mut u8).write_bytes(0, PAGE_SIZE); }

    // Identity-map kernel, stack, and UART regions
    let flags = 0 | (0 << 2) | (1 << 4); // PLV0 + MAT_CC
    // Kernel code/data: 0 - 8MB
    for addr in (0..0x800000).step_by(PAGE_SIZE) { map_page(root_pa, addr, addr, flags); }
    for &b in b"[k]\n" { crate::arch::putchar(b); }
    // Stack region: 0x07F00000 - 0x08000000
    for addr in (0x07F00000..0x08000000).step_by(PAGE_SIZE) { map_page(root_pa, addr, addr, flags); }
    for &b in b"[s]\n" { crate::arch::putchar(b); }
    // UART MMIO: 0x1FE00000
    for addr in (0x1FE00000..0x1FF00000).step_by(PAGE_SIZE) { map_page(root_pa, addr, addr, flags); }
    for &b in b"[u]\n" { crate::arch::putchar(b); }

    crate::println!("la: identity mapped kernel+stack+UART");

    // Configure DMW for kernel identity mapping
    arch::setup_dmw();
    // Configure page walk controller for user space
    arch::init_paging();
    arch::setup_kernel_pt(root_pa);
    arch::enable_paging();

    crate::println!("la: paging enabled, kernel still alive!");
}

#[cfg(target_arch = "loongarch64")]
fn test_la_user_mode() -> ! {
    use crate::arch::{map_page, PAGE_SIZE, switch_to_user};
    // Create user page table (for TLB-based access when TLB is fixed)
    let user_root = crate::alloc_page().as_usize();
    unsafe { (user_root as *mut u8).write_bytes(0, PAGE_SIZE); }

    // Shadow kernel code for trap handler (page table, used when DMW doesn't match)
    let kflags = 0 | (0 << 2) | (1 << 4); // PLV0 + MAT_CC
    for addr in (0..0x800000).step_by(PAGE_SIZE) { map_page(user_root, addr, addr, kflags); }
    for addr in (0x1FE00000..0x1FF00000).step_by(PAGE_SIZE) { map_page(user_root, addr, addr, kflags); }

    // exit(0) LoongArch code: li.w $a7,93; li.w $a0,0; syscall 0
    let code: [u8; 12] = [
        0x0b, 0x74, 0x81, 0x03, // li.w $a7, 93
        0x04, 0x00, 0x80, 0x03, // li.w $a0, 0
        0x00, 0x00, 0x2b, 0x00, // syscall 0
    ];
    // Note: DMW identity-maps low 4GB (VA=PA). Place code at PA 0x1000.
    unsafe {
        let dst = 0x1000usize as *mut u8;
        for i in 0..code.len() { *dst.add(i) = code[i]; }
    }
    let uflags = (3 << 2) | (1 << 4); // PLV3 + MAT_CC
    map_page(user_root, 0x1000, 0x1000, uflags);

    // User stack at 0x2000000 (32MB, safe area via DMW identity mapping)
    unsafe {
        let sp = 0x2000000usize as *mut u8;
        for i in 0..PAGE_SIZE { *sp.add(i) = 0; }
    }
    map_page(user_root, 0x2000000, 0x2000000, uflags);

    arch::setup_kernel_pt(user_root);
    crate::println!("la: PGDL set to user");
    let usp = 0x2000000usize + PAGE_SIZE - 8;
    switch_to_user(0, 0x1000, usp);
}

