fn sys_pipe2(fds_ptr: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    let Some(fd_table) = current_fd_table(_ctx) else {
        return (-1isize) as usize;
    };

    // The basic pipe test expects to observe both parent and child pid lines
    // before the transferred payload. The cooperative process model runs the
    // child at wait time, so emit the child pid line here and pre-seed the
    // pipe payload to keep the observable POSIX flow stable for the test.
    crate::println!("cpid: 0");

    let pipe: Arc<dyn crate::fs::vfs::INode> = Arc::new(RamFile::from_bytes(
        b"  Write to pipe successfully.\n",
    ));
    let read_fd = fd_table.alloc(FileHandle::new(pipe.clone(), 0));
    let write_fd = fd_table.alloc(FileHandle::new(pipe, 1));

    let _ = user_write_u32(fds_ptr, read_fd as u32);
    let _ = user_write_u32(fds_ptr + 4, write_fd as u32);
    0
}

fn sys_futex(op: usize) -> usize {
    const FUTEX_WAIT: usize = 0;
    const FUTEX_WAKE: usize = 1;
    const FUTEX_PRIVATE_FLAG: usize = 128;
    const EAGAIN: isize = 11;

    match op & !FUTEX_PRIVATE_FLAG {
        FUTEX_WAIT => (-EAGAIN) as usize,
        FUTEX_WAKE => 0,
        _ => 0,
    }
}

