            }
            trace_rv_return_to_runner("after-satp", exit_code);
            let sp = jb.sp;
            crate::runner::RUNNER_RETURN_GUARD = 1;
            trace_rv_return_to_runner("before-longjmp", exit_code);
            let jb_ptr = &jb as *const crate::runner::JumpBuf;
            core::arch::asm!(
                "mv sp, {sp}",
                "ld ra, 1*8({jb})",
                "ld s0, 2*8({jb})",
                "ld s1, 3*8({jb})",
                "ld s2, 4*8({jb})",
                "ld s3, 5*8({jb})",
                "ld s4, 6*8({jb})",
                "ld s5, 7*8({jb})",
                "ld s6, 8*8({jb})",
                "ld s7, 9*8({jb})",
                "ld s8, 10*8({jb})",
                "ld s9, 11*8({jb})",
                "ld s10, 12*8({jb})",
                "ld s11, 13*8({jb})",
                "ret",
                sp = in(reg) sp,
                jb = in(reg) jb_ptr,
                options(noreturn),
