// clone: like fork but child uses provided stack (musl wrapper expects this)
fn sys_clone(tf: &mut TrapFrame, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    use crate::task::scheduler;
    const CLONE_VM: usize = 0x0000_0100;
    const CLONE_THREAD: usize = 0x0001_0000;
    const CLONE_SETTLS: usize = 0x0008_0000;
    const CLONE_PARENT_SETTID: usize = 0x0010_0000;
    const CLONE_CHILD_CLEARTID: usize = 0x0020_0000;
    const CLONE_CHILD_SETTID: usize = 0x0100_0000;

    let flags = tf.arg0();
    #[cfg(target_arch = "loongarch64")]
    if option_env!("LA_REAL_LIBCBENCH").is_some()
        && option_env!("LA_FORCE_LIBCBENCH_COMPAT").is_none()
    {
        if flags & (CLONE_VM | CLONE_THREAD | CLONE_SETTLS) != 0 {
            return (-EAGAIN) as usize;
        }
    }

    let unsupported_thread_bits = CLONE_VM | CLONE_THREAD | CLONE_SETTLS;
    if flags & unsupported_thread_bits != 0 {
        return (-EAGAIN) as usize;
    }

    let child_stack = tf.arg1(); // clone(child_stack) from musl
    let child_stack = if child_stack == 0 { None } else { Some(child_stack) };
    if let Some(ref proc) = scheduler::current_process() {
        if let Some(child_pid) = scheduler::fork_process(proc, tf, child_stack) {
            if flags & CLONE_PARENT_SETTID != 0 {
                let _ = user_write_u32(tf.arg2(), child_pid);
            }
            if flags & (CLONE_CHILD_SETTID | CLONE_CHILD_CLEARTID) != 0 {
                let child_tid = if tf.arg3() != 0 { tf.arg3() } else { tf.arg4() };
                if child_tid != 0 {
                    let _ = user_write_u32(child_tid, child_pid);
                }
            }
            return child_pid as usize;
        }
    }
    0
}

