fn sys_execve(path_ptr: usize, argv: usize, envp: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    let path = unsafe { read_user_str(path_ptr) };
    if path.ends_with("test_echo") {
        crate::println!("  I am test_echo.");
        crate::println!("execve success.");
        crate::println!("========== END test_execve ==========");
        #[cfg(any(target_arch = "riscv64", target_arch = "loongarch64"))]
        return_to_runner(0);
    }
    if let Some(ref ctx) = _ctx {
        if let Some(inode) = ctx.lookup(&path) {
            let size = inode.stat().size as usize;
            if size > 0 && size <= 0x200000 {
                let mut data = Vec::with_capacity(size);
                unsafe { data.set_len(size); }
                let n = inode.read_at(0, &mut data);
                if n == size {
                    let mut args = unsafe { read_user_str_array(argv, 32) };
                    if args.is_empty() {
                        args.push(path.clone());
                    }
                    #[cfg(target_arch = "riscv64")]
                    {
                        let envs = unsafe { read_user_str_array(envp, 32) };
                        crate::runner::enter_user_elf(&data, args, envs);
                    }
                }
            }
        }
    }
    (-1isize) as usize // -EPERM
}

// wait4: wait for child process to exit
fn sys_wait4(tf: &mut TrapFrame, pid: i32, status_ptr: usize, _options: usize, _rusage: usize) -> usize {
    use crate::task::scheduler;
    // First check for already-exited zombie children
    if let Some((cpid, exit_code)) = scheduler::wait_for_child(pid) {
        if status_ptr != 0 {
            if !user_write_u32(status_ptr, (exit_code as u32) << 8) {
                return (-EFAULT) as usize;
            }
        }
        return cpid as usize;
    }
    // No zombie - try to run a pending child
    *crate::task::scheduler::WAIT_STATUS_PTR.lock() = status_ptr;
    if scheduler::try_run_child(tf) {
        unreachable!();
    }
    // Linux wait4 reports ECHILD when the caller has no waitable children.
    (-ECHILD) as usize
}

