fn sys_writev(fd: usize, iov_ptr: usize, iovcnt: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    let mut total: usize = 0;
    for i in 0..iovcnt {
        // iovec { iov_base: *mut u8, iov_len: usize }
        let iov = unsafe {
            let base = *((iov_ptr + i * 16) as *const usize);
            let len = *((iov_ptr + i * 16 + 8) as *const usize);
            (base, len)
        };
        let n = sys_write(fd, iov.0, iov.1, _ctx);
        if n > iov.1 {
            return if total == 0 { n } else { total };
        }
        total += n;
        if n < iov.1 {
            break;
        }
    }
    total
}

fn sys_readv(fd: usize, iov_ptr: usize, iovcnt: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    let mut total: usize = 0;
    for i in 0..iovcnt {
        let base = unsafe { *((iov_ptr + i * 16) as *const usize) };
        let len = unsafe { *((iov_ptr + i * 16 + 8) as *const usize) };
        let n = sys_read(fd, base, len, _ctx);
        if n > len {
            return if total == 0 { n } else { total };
        }
        total += n;
        if n < len {
            break;
        }
    }
    total
}

fn sys_fcntl(fd: usize, cmd: usize, arg: usize, _ctx: &Option<Arc<context::ProcessContext>>) -> usize {
    let Some(fd_table) = current_fd_table(_ctx) else {
        return (-1isize) as usize;
    };
    let Some(fh) = fd_table.get(fd) else {
        return (-1isize) as usize;
    };

    match cmd {
        0 => fd_table.alloc_shared_min(arg, fh), // F_DUPFD
        1 => 0,                                 // F_GETFD
        2 => 0,                                 // F_SETFD
        3 => fh.lock().flags as usize,          // F_GETFL
        4 => {
            fh.lock().flags = arg as u32;
            0
        }
        _ => 0,
    }
}

fn sys_getrandom(buf: usize, len: usize) -> usize {
    const CHUNK: usize = 64;
    let mut out = [0u8; CHUNK];
    let mut done = 0usize;
    while done < len {
        let n = (len - done).min(CHUNK);
        for i in 0..n {
            out[i] = (0x5ausize.wrapping_add((done + i) * 37) & 0xff) as u8;
        }
        if !user_write_bytes(buf + done, &out[..n]) {
            return (-14isize) as usize;
        }
        done += n;
    }
    len
}

