#[cfg(target_arch = "riscv64")]
fn return_to_runner(exit_code: usize) -> ! {
    unsafe {
        if let Some(jb) = crate::runner::RUNNER_JB {
            trace_rv_return_to_runner("enter", exit_code);
            crate::runner::RUNNER_EXIT_CODE = exit_code;
            trace_rv_return_to_runner("before-reclaim", exit_code);
            reclaim_runner_user_space();
            trace_rv_return_to_runner("after-reclaim", exit_code);
            let kernel_satp = *KERNEL_SATP.lock();
            if kernel_satp != 0 {
                if let Some(ref proc) = crate::task::scheduler::current_process() {
                    *proc.page_table_root.lock() = kernel_satp;
                }
                core::arch::asm!(
                    "csrw satp, {satp}",
                    "sfence.vma",
                    satp = in(reg) kernel_satp,
                    options(nostack),
                );
            }
            trace_rv_return_to_runner("after-satp", exit_code);
            let sp = jb.sp;
            crate::runner::RUNNER_RETURN_GUARD = 1;
            trace_rv_return_to_runner("before-longjmp", exit_code);
            let jb_ptr = &jb as *const crate::runner::JumpBuf;
            core::arch::asm!(
                "mv sp, {sp}",
                "ld ra, 1*8({jb})",
                "ld s0, 2*8({jb})",
                "ld s1, 3*8({jb})",
                "ld s2, 4*8({jb})",
                "ld s3, 5*8({jb})",
                "ld s4, 6*8({jb})",
                "ld s5, 7*8({jb})",
                "ld s6, 8*8({jb})",
                "ld s7, 9*8({jb})",
                "ld s8, 10*8({jb})",
                "ld s9, 11*8({jb})",
                "ld s10, 12*8({jb})",
                "ld s11, 13*8({jb})",
                "ret",
                sp = in(reg) sp,
                jb = in(reg) jb_ptr,
                options(noreturn),
            );
        }
    }
    crate::arch::arch_shutdown();
}

