#[cfg(target_arch = "loongarch64")]
fn return_to_runner(exit_code: usize) -> ! {
    unsafe {
        if let Some(ref jb) = crate::runner::RUNNER_JB {
            crate::runner::RUNNER_EXIT_CODE = exit_code;
            reclaim_runner_user_space();
            if let Some(ref proc) = crate::task::scheduler::current_process() {
                *proc.page_table_root.lock() = *KERNEL_SATP.lock();
            }
            crate::arch::disable_paging();
            let sp = jb.sp;
            crate::runner::RUNNER_RETURN_GUARD = 1;
            let jb_ptr = jb as *const crate::runner::JumpBuf;
            core::arch::asm!(
                "ori $sp, {sp}, 0",
                "addi.d $r12, {jb}, 8",
                "ld.d $r1, $r12, 0",
                "ld.d $r22, $r12, 8",
                "ld.d $r23, $r12, 16",
                "ld.d $r24, $r12, 24",
                "ld.d $r25, $r12, 32",
                "ld.d $r26, $r12, 40",
                "ld.d $r27, $r12, 48",
                "ld.d $r28, $r12, 56",
                "ld.d $r29, $r12, 64",
                "ld.d $r30, $r12, 72",
                "ld.d $r31, $r12, 80",
                "ori $r4, $zero, 1",
                "jr $r1",
                sp = in(reg) sp,
                jb = in(reg) jb_ptr,
                options(noreturn),
            );
        }
    }
    crate::arch::arch_shutdown();
}

fn reclaim_runner_user_space() {
    const HEAP_START: usize = 0x20000000;
    let ranges = USER_RECLAIM_RANGES.lock();
    for i in 0..ranges.len {
        let (start, end) = ranges.ranges[i];
        reclaim_user_pages(start, end);
    }
    drop(ranges);

    unsafe {
        let brk_end = align_up_usize(BRK_END, crate::memory::address::PAGE_SIZE);
        if brk_end > HEAP_START {
            reclaim_user_pages(HEAP_START, brk_end);
        }
        if ANON_MMAP_HIGH > ANON_MMAP_LOW {
            reclaim_user_pages(ANON_MMAP_LOW, ANON_MMAP_HIGH);
        }
    }
}

