const PTE_PLV3: usize = 3 << 2; // user
const PTE_MAT_CC: usize = 1 << 4; // coherent cached (MAT=1)
const PTE_PRESENT: usize = 1 << 7; // present/page size (0=4K leaf)
const PTE_GLOBAL: usize = 1 << 6; // global TLB entry

// Three-level page table (SV39-like): PGD→PMD→PTE
