pub fn la_pte(ppn: usize, flags: usize) -> usize {
    // PTE format: PPN[63:12] at [63:12], flags at [11:0]
    // bit7=P (page size: 0=4KB), so PRESENT is NOT a separate bit
    (ppn << 12) | flags | PTE_VALID | PTE_DIRTY | PTE_MAT_CC | PTE_GLOBAL
}

