    fn read_sector_mmio(&mut self, sector: u64, buf: &mut [u8; SECTOR_SIZE]) -> bool {
        const READ_ATTEMPTS: usize = 4;
        let mut last = ReadResult::Timeout;
        for attempt in 0..READ_ATTEMPTS {
            match self.read_sector_mmio_once(sector, buf) {
                ReadResult::Ok => return true,
                result => {
                    last = result;
                    if attempt + 1 < READ_ATTEMPTS {
                        self.reset_mmio_queue();
                    }
                }
            }
        }

        unsafe {
            match last {
                ReadResult::Ok => {}
                ReadResult::DeviceError(status) => {
                    crate::println!(
                        "virtio-mmio: read failed sector={} base=0x{:x} avail={} used={} status=0x{:02x}",
                        sector,
                        self.base,
                        core::ptr::read_volatile(&raw const DMA.avail.idx),
                        core::ptr::read_volatile(&raw const DMA.used.idx),
                        status,
                    );
                }
                ReadResult::Timeout => {
                    crate::println!(
                        "virtio-mmio: read timeout sector={} base=0x{:x} avail={} used={} status=0x{:02x}",
                        sector,
                        self.base,
                        core::ptr::read_volatile(&raw const DMA.avail.idx),
                        core::ptr::read_volatile(&raw const DMA.used.idx),
                        core::ptr::read_volatile(&raw const DMA.status),
                    );
                }
            }
        }
        false
    }

    fn read_sector_mmio_once(&mut self, sector: u64, buf: &mut [u8; SECTOR_SIZE]) -> ReadResult {
        unsafe {
            DMA.header = BlkReqHeader { req_type: BLK_T_IN, reserved: 0, sector };
            DMA.data = [0; SECTOR_SIZE];
            DMA.status = 0xff;

            let dp = &raw const DMA as u64;
            DMA.desc[0] = VirtqDesc { addr: dp + core::mem::offset_of!(VirtIoDma, header) as u64, len: 16, flags: VRING_DESC_F_NEXT, next: 1 };
            DMA.desc[1] = VirtqDesc { addr: dp + core::mem::offset_of!(VirtIoDma, data) as u64, len: SECTOR_SIZE as u32, flags: VRING_DESC_F_NEXT | VRING_DESC_F_WRITE, next: 2 };
            DMA.desc[2] = VirtqDesc { addr: dp + core::mem::offset_of!(VirtIoDma, status) as u64, len: 1, flags: VRING_DESC_F_WRITE, next: 0 };

            let s = DMA.avail.idx as usize % QUEUE_SIZE;
            DMA.avail.ring[s] = 0;
            dma_fence();
            DMA.avail.idx = DMA.avail.idx.wrapping_add(1);
            dma_fence();

            w32(self.base, 0x50, 0);

            for _ in 0..20_000_000 {
                let ui = core::ptr::read_volatile(&raw const DMA.used.idx);
                if ui != self.last_used {
                    self.last_used = self.last_used.wrapping_add(1);
                    let status = core::ptr::read_volatile(&raw const DMA.status);
                    if status == 0 {
                        dma_fence();
                        buf.copy_from_slice(&DMA.data);
                        return ReadResult::Ok;
                    }
                    return ReadResult::DeviceError(status);
                }
                core::hint::spin_loop();
            }
        }
        ReadResult::Timeout
    }

    fn reset_mmio_queue(&mut self) {
        unsafe {
            let ver = r32(self.base, 0x04);
            w32(self.base, 0x70, 0);
            w32(self.base, 0x70, VIRTIO_STATUS_ACKNOWLEDGE);
            w32(self.base, 0x70, VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER);

            if ver == 2 {
                w32(self.base, 0x10, 0);
                w32(self.base, 0x20, 0);
                w32(self.base, 0x70, VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER | VIRTIO_STATUS_FEATURES_OK);
            }

            w32(self.base, 0x30, 0);
            w32(self.base, 0x38, QUEUE_SIZE as u32);
            core::ptr::write_bytes(&raw mut DMA as *mut u8, 0, core::mem::size_of::<VirtIoDma>());

            let dma_phys = &raw const DMA as usize;
            if ver == 2 {
                w32(self.base, 0x080, dma_phys as u32);
                w32(self.base, 0x084, (dma_phys >> 32) as u32);
                let av = dma_phys + core::mem::offset_of!(VirtIoDma, avail);
                w32(self.base, 0x090, av as u32);
                w32(self.base, 0x094, (av >> 32) as u32);
                let us = dma_phys + core::mem::offset_of!(VirtIoDma, used);
                w32(self.base, 0x0a0, us as u32);
                w32(self.base, 0x0a4, (us >> 32) as u32);
                w32(self.base, 0x044, 1);
            } else {
                w32(self.base, 0x028, 4096);
                w32(self.base, 0x03c, 4096);
                w32(self.base, 0x040, (dma_phys / 4096) as u32);
            }
            dma_fence();
            w32(self.base, 0x70, VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER | VIRTIO_STATUS_DRIVER_OK);
            self.last_used = 0;
        }
    }

